import React, { useState, useEffect } from 'react';
import { useSearchParams } from 'react-router-dom';
import { Plane, Clock, Filter, ChevronDown, ArrowRight, Wifi, Luggage, Star } from 'lucide-react';
import api from '../utils/api';
import '../styles/flights.css';

const MOCK_FLIGHTS = [
  { _id: '1', flightNumber: 'DT101', airline: { name: 'DataAir', code: 'DT', logo: '✈' }, departure: '06:00', arrival: '08:15', duration: '2h 15m', stops: 0, cabins: { economy: { price: 3299, available: 45, baggage: '15 kg' } }, amenities: ['wifi', 'meal'], refundable: true },
  { _id: '2', flightNumber: 'IA512', airline: { name: 'Air India', code: 'AI', logo: '✈' }, departure: '09:30', arrival: '11:55', duration: '2h 25m', stops: 0, cabins: { economy: { price: 3850, available: 32, baggage: '15 kg' } }, amenities: ['meal'], refundable: false },
  { _id: '3', flightNumber: '6E345', airline: { name: 'IndiGo', code: '6E', logo: '✈' }, departure: '13:00', arrival: '15:10', duration: '2h 10m', stops: 0, cabins: { economy: { price: 2899, available: 18, baggage: '15 kg' } }, amenities: [], refundable: false },
  { _id: '4', flightNumber: 'SG788', airline: { name: 'SpiceJet', code: 'SG', logo: '✈' }, departure: '16:45', arrival: '19:05', duration: '2h 20m', stops: 0, cabins: { economy: { price: 3100, available: 7, baggage: '15 kg' } }, amenities: ['meal'], refundable: true },
  { _id: '5', flightNumber: 'UK234', airline: { name: 'Vistara', code: 'UK', logo: '✈' }, departure: '07:15', arrival: '10:30', duration: '3h 15m', stops: 1, cabins: { economy: { price: 4200, available: 22, baggage: '20 kg' } }, amenities: ['wifi', 'meal', 'entertainment'], refundable: true },
  { _id: '6', flightNumber: 'I5890', airline: { name: 'Air Asia', code: 'I5', logo: '✈' }, departure: '20:00', arrival: '22:15', duration: '2h 15m', stops: 0, cabins: { economy: { price: 2600, available: 3, baggage: '15 kg' } }, amenities: [], refundable: false },
];

export default function FlightSearchPage() {
  const [searchParams] = useSearchParams();
  const [flights, setFlights] = useState(MOCK_FLIGHTS);
  const [loading, setLoading] = useState(false);
  const [sortBy, setSortBy] = useState('price');
  const [filters, setFilters] = useState({ stops: 'all', maxPrice: '', airlines: [] });
  const [showFilters, setShowFilters] = useState(true);

  const from = searchParams.get('fromCity') || searchParams.get('from') || 'Delhi';
  const to = searchParams.get('toCity') || searchParams.get('to') || 'Mumbai';
  const date = searchParams.get('date') || '';
  const adults = Number(searchParams.get('adults') || 1);
  const cabin = searchParams.get('cabin') || 'Economy';

  const sorted = [...flights].sort((a, b) => {
    if (sortBy === 'price') return a.cabins.economy.price - b.cabins.economy.price;
    if (sortBy === 'duration') return a.duration.localeCompare(b.duration);
    if (sortBy === 'departure') return a.departure.localeCompare(b.departure);
    return 0;
  });

  const filtered = sorted.filter(f => {
    if (filters.stops !== 'all' && f.stops !== Number(filters.stops)) return false;
    if (filters.maxPrice && f.cabins.economy.price > Number(filters.maxPrice)) return false;
    if (filters.airlines.length > 0 && !filters.airlines.includes(f.airline.code)) return false;
    return true;
  });

  const airlines = [...new Set(flights.map(f => f.airline.name))];

  return (
    <div className="flight-search-page">
      <div className="fsp-header">
        <div className="container">
          <div className="fsp-route">
            <span className="fsp-city">{from}</span>
            <span className="fsp-icon"><Plane size={20} /></span>
            <span className="fsp-city">{to}</span>
            <span className="fsp-meta">{date} · {adults} Adult · {cabin}</span>
          </div>
          <div className="fsp-sort">
            <span className="sort-label">Sort by:</span>
            {['price', 'duration', 'departure'].map(s => (
              <button key={s} className={`sort-btn ${sortBy === s ? 'sort-active' : ''}`} onClick={() => setSortBy(s)}>
                {s.charAt(0).toUpperCase() + s.slice(1)}
              </button>
            ))}
          </div>
        </div>
      </div>

      <div className="fsp-body container">
        {/* Filters Sidebar */}
        <aside className={`filters-sidebar ${showFilters ? 'filters-open' : ''}`}>
          <div className="filter-section">
            <h4>Stops</h4>
            {['all', '0', '1'].map(s => (
              <label key={s} className="filter-option">
                <input type="radio" name="stops" value={s} checked={filters.stops === s} onChange={() => setFilters({ ...filters, stops: s })} />
                {s === 'all' ? 'Any' : s === '0' ? 'Non-stop' : '1 Stop'}
              </label>
            ))}
          </div>
          <div className="filter-section">
            <h4>Airlines</h4>
            {airlines.map(a => (
              <label key={a} className="filter-option">
                <input type="checkbox" checked={filters.airlines.includes(a.split(' ')[0])}
                  onChange={e => setFilters({ ...filters, airlines: e.target.checked ? [...filters.airlines, a.split(' ')[0]] : filters.airlines.filter(x => x !== a.split(' ')[0]) })} />
                {a}
              </label>
            ))}
          </div>
          <div className="filter-section">
            <h4>Max Price (₹)</h4>
            <input type="range" min="1500" max="10000" step="500" value={filters.maxPrice || 10000}
              onChange={e => setFilters({ ...filters, maxPrice: e.target.value })} className="price-range" />
            <div className="price-range-label">Up to ₹{filters.maxPrice || 10000}</div>
          </div>
          <button className="reset-filters" onClick={() => setFilters({ stops: 'all', maxPrice: '', airlines: [] })}>Reset Filters</button>
        </aside>

        {/* Flight Results */}
        <div className="flight-results">
          <div className="results-count">{filtered.length} flights found</div>

          {loading ? (
            <div className="loading-state">Searching for best fares...</div>
          ) : filtered.length === 0 ? (
            <div className="no-results">No flights found. Try adjusting your filters.</div>
          ) : (
            filtered.map(flight => (
              <div key={flight._id} className="flight-card">
                <div className="fc-airline">
                  <div className="fc-airline-logo">{flight.airline.logo}</div>
                  <div>
                    <div className="fc-airline-name">{flight.airline.name}</div>
                    <div className="fc-flight-no">{flight.flightNumber}</div>
                  </div>
                </div>

                <div className="fc-times">
                  <div className="fc-time">
                    <div className="fc-hour">{flight.departure}</div>
                    <div className="fc-city">{from}</div>
                  </div>
                  <div className="fc-duration">
                    <div className="fc-dur-line"><div className="fc-line" />{flight.stops > 0 && <div className="fc-stop-dot" />}<div className="fc-line" /></div>
                    <div className="fc-dur-text">{flight.duration}</div>
                    <div className="fc-stops-text">{flight.stops === 0 ? 'Non-stop' : `${flight.stops} stop`}</div>
                  </div>
                  <div className="fc-time">
                    <div className="fc-hour">{flight.arrival}</div>
                    <div className="fc-city">{to}</div>
                  </div>
                </div>

                <div className="fc-meta">
                  {flight.amenities.map(a => (
                    <span key={a} className="fc-amenity">{a === 'wifi' ? '📶' : a === 'meal' ? '🍽' : '🎬'} {a}</span>
                  ))}
                  <span className={`fc-seats ${flight.cabins.economy.available <= 5 ? 'seats-low' : ''}`}>
                    {flight.cabins.economy.available <= 5 ? `⚡ ${flight.cabins.economy.available} left!` : `${flight.cabins.economy.available} seats`}
                  </span>
                  {flight.refundable && <span className="fc-refund">✓ Refundable</span>}
                  <span className="fc-baggage">🧳 {flight.cabins.economy.baggage}</span>
                </div>

                <div className="fc-price-col">
                  <div className="fc-price">₹{(flight.cabins.economy.price * adults).toLocaleString()}</div>
                  <div className="fc-price-sub">per {adults > 1 ? `${adults} adults` : 'adult'} · {cabin}</div>
                  <button className="fc-book-btn" onClick={() => alert(`Booking ${flight.flightNumber}! Integrate with Booking API.`)}>
                    Book Now <ArrowRight size={16} />
                  </button>
                </div>
              </div>
            ))
          )}
        </div>
      </div>
    </div>
  );
}
